/**
 * @summary Update product details and replace images if provided
 */
export type productUpdateResponse200 = {
  data: ProductUpdate200
  status: 200
}

export type productUpdateResponse401 = {
  data: AuthenticationExceptionResponse
  status: 401
}

export type productUpdateResponse404 = {
  data: ModelNotFoundExceptionResponse
  status: 404
}

export type productUpdateResponse422 = {
  data: ValidationExceptionResponse
  status: 422
}

export type productUpdateResponseSuccess = (productUpdateResponse200) & {
  headers: Headers;
};
export type productUpdateResponseError = (productUpdateResponse401 | productUpdateResponse404 | productUpdateResponse422) & {
  headers: Headers;
};

export type productUpdateResponse = (productUpdateResponseSuccess | productUpdateResponseError)

export const getProductUpdateUrl = (product: number,) => {


  

  return `/products/${product}`
}

export const productUpdate = async (product: number,
    updateProductRequest: UpdateProductRequest, options?: RequestInit): Promise<productUpdateResponse> => {
    const formData = new FormData();
if(updateProductRequest.name !== undefined) {
 formData.append(`name`, updateProductRequest.name);
 }
if(updateProductRequest.description !== undefined) {
 formData.append(`description`, updateProductRequest.description);
 }
if(updateProductRequest.costPrice !== undefined) {
 formData.append(`costPrice`, updateProductRequest.costPrice.toString())
 }
if(updateProductRequest.sellPrice !== undefined) {
 formData.append(`sellPrice`, updateProductRequest.sellPrice.toString())
 }
if(updateProductRequest.currentQuantity !== undefined) {
 formData.append(`currentQuantity`, updateProductRequest.currentQuantity.toString())
 }
if(updateProductRequest.reorderLevel !== undefined) {
 formData.append(`reorderLevel`, updateProductRequest.reorderLevel.toString())
 }
if(updateProductRequest.reorderQuantity !== undefined) {
 formData.append(`reorderQuantity`, updateProductRequest.reorderQuantity.toString())
 }
if(updateProductRequest.images !== undefined && updateProductRequest.images !== null) {
 const imageFiles = Array.isArray(updateProductRequest.images) ? updateProductRequest.images : [updateProductRequest.images];
 imageFiles.forEach((file) => {
 formData.append(`images[]`, file as Blob);
 });
 }

  const res = await fetch(getProductUpdateUrl(product),
  {      
    ...options,
    method: 'PUT'
    ,
    body: 
      formData,
  }
)

  const body = [204, 205, 304].includes(res.status) ? null : await res.text();
  
  const data: productUpdateResponse['data'] = body ? JSON.parse(body) : {}
  return { data, status: res.status, headers: res.headers } as productUpdateResponse
}
  


